import type {
  OTPFieldsetCharacterConfig,
  OTPFieldsetCharacterTransform,
} from "./OTPFieldset.config";
import { DEFAULT_OTP_FIELDSET_CHARACTER_CONFIG } from "./OTPFieldset.config";

/**
 * Zero-width space used as a placeholder for empty positions.
 * This allows the value string to preserve gaps when cells are not filled sequentially.
 * Must always be allowed through character filtering to preserve gaps.
 */
export const EMPTY_PLACEHOLDER = "\u200B";

// =============================================================================
// Value Parsing & Serialization
// =============================================================================

/**
 * Parses a string value into an array of individual characters,
 * padded to the specified length with empty strings.
 * Treats the placeholder character as empty.
 */
export function parseValueToArray(
  value: string | undefined,
  length: number
): string[] {
  const chars = (value ?? "").split("");
  const result: string[] = [];
  for (let i = 0; i < length; i++) {
    const char = chars[i] ?? "";
    // Treat placeholder as empty for display purposes
    result.push(char === EMPTY_PLACEHOLDER ? "" : char);
  }
  return result;
}

/**
 * Joins an array of characters into a single string value.
 * Uses the placeholder character for empty positions to preserve gaps.
 */
export function joinArrayToValue(values: string[]): string {
  return values.map((v) => (v === "" ? EMPTY_PLACEHOLDER : v)).join("");
}

/**
 * Removes placeholder characters from a value string.
 * Used for form submission to get the actual entered characters.
 */
export function cleanValue(value: string): string {
  return value.replace(new RegExp(EMPTY_PLACEHOLDER, "g"), "");
}

/**
 * Checks if all positions in the OTP value are filled with actual characters.
 * Returns true when the cleaned value (without placeholders) has the expected length.
 */
export function isComplete(value: string, length: number): boolean {
  return cleanValue(value).length === length;
}

// =============================================================================
// Character Configuration
// =============================================================================

/**
 * Type for the characterConfig prop.
 */
export type CharacterConfigProp = Partial<OTPFieldsetCharacterConfig>;

/**
 * Resolves a character config prop (partial config) to a full config.
 */
export function resolveCharacterConfig(
  config?: CharacterConfigProp
): OTPFieldsetCharacterConfig {
  if (config === undefined) {
    return DEFAULT_OTP_FIELDSET_CHARACTER_CONFIG;
  }

  return {
    ...DEFAULT_OTP_FIELDSET_CHARACTER_CONFIG,
    ...config,
  };
}

// =============================================================================
// Character Processing
// =============================================================================

/**
 * Tests if a character matches the whitelist pattern.
 * Returns true if the character is allowed, false otherwise.
 */
function isCharacterAllowed(char: string, whitelistedChars: string): boolean {
  // Special case: "*" allows all characters
  if (whitelistedChars === "*") {
    return true;
  }

  try {
    const regex = new RegExp(whitelistedChars);
    return regex.test(char);
  } catch {
    // If the regex is invalid, allow the character
    return true;
  }
}

/**
 * Applies the transform to a character.
 */
function applyTransform(
  char: string,
  transform: OTPFieldsetCharacterTransform
): string {
  switch (transform) {
    case "uppercase":
      return char.toUpperCase();
    case "lowercase":
      return char.toLowerCase();
    default:
      return char;
  }
}

/**
 * Processes a single character through the character config.
 * Returns the transformed character if allowed, or null if filtered out.
 * The empty placeholder character is always preserved without transformation.
 */
export function processCharacter(
  char: string,
  config: OTPFieldsetCharacterConfig
): string | null {
  // Always preserve the placeholder character used for empty positions
  if (char === EMPTY_PLACEHOLDER) {
    return char;
  }

  if (!isCharacterAllowed(char, config.whitelistedChars)) {
    return null;
  }

  return applyTransform(char, config.transform ?? "none");
}

/**
 * Processes a string through the character config.
 * Filters out disallowed characters and applies transformations.
 */
export function processString(
  value: string,
  config: OTPFieldsetCharacterConfig
): string {
  return value
    .split("")
    .map((char) => processCharacter(char, config))
    .filter((char): char is string => char !== null)
    .join("");
}
