import { InputSize } from "../Input";

export const OTPFieldsetSizes = ["sm", "md", "lg"] as const;
export type OTPFieldsetSize = (typeof OTPFieldsetSizes)[number];

export const OTPFieldsetCharacterTransforms = [
  "none",
  "uppercase",
  "lowercase",
] as const;
export type OTPFieldsetCharacterTransform =
  (typeof OTPFieldsetCharacterTransforms)[number];

export interface OTPFieldsetCharacterConfig {
  /**
   * A regex pattern string to test each character against.
   * Characters that don't match will be ignored.
   * Use "*" to allow all characters.
   * @example "[0-9]" // numeric only
   * @example "[a-zA-Z0-9]" // alphanumeric only
   * @example "[a-fA-F0-9]" // hex characters only
   */
  whitelistedChars: string;
  /**
   * Transform to apply to accepted characters.
   * @default "none"
   */
  transform?: OTPFieldsetCharacterTransform;
}

// Defaults
export const DEFAULT_OTP_FIELDSET_SIZE: OTPFieldsetSize = "md";
export const DEFAULT_OTP_FIELDSET_LENGTH = 6;
export const DEFAULT_OTP_FIELDSET_CHARACTER_CONFIG: OTPFieldsetCharacterConfig =
  {
    whitelistedChars: "[0-9]",
    transform: "none",
  };

/**
 * Maps OTPFieldset size to Input size.
 * Input only supports "sm" and "md", so "lg" is mapped to "md"
 * and OTPFieldset handles the height override in CSS.
 */
export const SIZE_TO_INPUT_SIZE: Record<OTPFieldsetSize, InputSize> = {
  sm: "sm",
  md: "md",
  lg: "md",
};
